const body = $json.body ?? $json;
const traceId = body.traceId || body.jobId || `trace-${Date.now()}`;

let userText = String(body.userText || '').trim();
userText = userText.replace(/[\u2018\u2019]/g, "'").replace(/[\u201C\u201D]/g, '"');
userText = userText.replace(/[ \t\n\r]+/g, ' ').trim().slice(0, 500);

const locale = String(body.locale || body.voiceLanguage || 'en').slice(0, 16);
const systemPrompt = String(body.systemPrompt || '').trim().slice(0, 2000);
const config = (body.config && typeof body.config === 'object') ? body.config : {};
const messages = (Array.isArray(body.messages) ? body.messages : [])
  .filter(m => m && String(m.content || '').trim().length > 0)
  .slice(-10);

return [{ json: {
  traceId,
  roomId: body.roomId || null,
  jobId: body.jobId || null,
  userId: body.userId || null,
  deviceId: body.deviceId || null,
  userText,
  messages,
  locale,
  systemPrompt,
  config,
  startedAt: new Date().toISOString()
}}];

const body = $json;
const pCfg = body.config || {};

function resolve(pv, varName, def) {
  if (pv != null && pv !== '') return pv;
  try { const nv = $vars[varName]; if (nv != null && nv !== '') return nv; } catch {}
  return def;
}

const cfg = {
  intentModel:       resolve(pCfg.intentModel,   'INTENT_MODEL',    'ministral-3:8b'),
  intentBaseUrl:     resolve(pCfg.intentBaseUrl,  'INTENT_BASE_URL', 'https://ollama.drascom.uk').replace(/\/$/, ''),
  intentTemperature: parseFloat(resolve(pCfg.intentTemperature, 'INTENT_TEMPERATURE', 0.1)) || 0.1,
  replyModel:        resolve(pCfg.replyModel,     'REPLY_MODEL',     'ministral-3:8b'),
  replyBaseUrl:      resolve(pCfg.replyBaseUrl,   'REPLY_BASE_URL',  'https://ollama.drascom.uk').replace(/\/$/, ''),
  replyTemperature:  parseFloat(resolve(pCfg.replyTemperature, 'REPLY_TEMPERATURE', 0.25)) || 0.25,
  replyMaxTokens:    parseInt(resolve(pCfg.replyMaxTokens, 'REPLY_MAX_TOKENS', 150)) || 150,
};

return [{ json: { ...body, cfg } }];

