const root = $json;
const raw = root?.choices?.[0]?.message?.content || '';
let parsed = {};
try {
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch { parsed = {}; }

const prev = $('Resolve Config').item.json;
const cfg = prev.cfg || {};

const VALID = new Set(['greeting','farewell','menu_browse','product_search','price_check','add_to_cart','view_cart','checkout','order_status','help','fallback']);
const intent = VALID.has(parsed.intent) ? parsed.intent : 'fallback';
const confidence = typeof parsed.confidence === 'number' ? Math.min(1, Math.max(0, parsed.confidence)) : 0.7;
const slots = { productName: parsed.slots?.productName || null, quantity: parsed.slots?.quantity || null };
const ask = String(parsed.ask || '');

return [{ json: { ...prev, intent, confidence, slots, ask, intentRaw: raw } }];

const llmText = String($json?.choices?.[0]?.message?.content || '').trim();
const ctx = $('Parse Intent').item.json;
return [{ json: { replyText: llmText || 'Here are the available options.', actions: [], meta: { intent: ctx.intent, traceId: ctx.traceId, locale: ctx.locale } } }];

const llmText = String($json?.choices?.[0]?.message?.content || '').trim();
const ctx = $('Parse Intent').item.json;
return [{ json: { replyText: llmText || 'Added to your cart.', actions: [], meta: { intent: ctx.intent, traceId: ctx.traceId } } }];

const llmText = String($json?.choices?.[0]?.message?.content || '').trim();
const ctx = $('Parse Intent').item.json;
const orderId = $('Create Order').item?.json?.data?.orderId || null;
return [{ json: { replyText: llmText || (orderId ? 'Your order has been placed.' : 'I could not place the order, please try again.'), actions: orderId ? [{ name: 'navigate', params: { screen: 'OrderDetail', orderId } }] : [], meta: { intent: 'checkout', traceId: ctx.traceId, orderId } } }];

const llmText = String($json?.choices?.[0]?.message?.content || '').trim();
const ctx = $('Parse Intent').item.json;
return [{ json: { replyText: llmText || 'Your cart is empty. Please add some items first.', actions: [], meta: { intent: ctx.intent, traceId: ctx.traceId } } }];

const llmText = String($json?.choices?.[0]?.message?.content || '').trim();
const ctx = $('Parse Intent').item.json;

const fallback = ctx.ask || (ctx.intent === 'fallback' ? "I'm not sure I understood. Could you rephrase?" : 'How can I help you with your order?');

return [{ json: {
  replyText: llmText || fallback,
  actions: [],
  meta: {
    intent: ctx.intent,
    confidence: ctx.confidence,
    slots: ctx.slots,
    traceId: ctx.traceId,
    locale: ctx.locale,
    model: ctx.cfg?.replyModel
  }
}}];
